    if isinstance(l, str):
        raise ValueError(f"Input of type'str' is not supported!")
    if isinstance(l, tuple):
        raise ValueError(f"Input of type 'tuple' is not supported!")
    if isinstance(l, dict):
        raise ValueError(f"Input of type 'dict' is not supported!")
